previewCss:
.darma-loader-darma-custom-347 {color: var(--loader-color, #7c3aed);
  --loader-secondary-color: #c084fc;
  --loader-bg: #ffffff;
  display: inline-grid;
  width: 80px;
  aspect-ratio: 2;
  overflow: hidden;
  border-image: 1 0/0 0 8px/0 0 8pxrepeating-linear-gradient(90deg,var(--loader-secondary-color, #c084fc) 0 26%,var(--loader-color, #7c3aed) 0 52%);
}.darma-loader-darma-custom-347:before {content:"";
  margin: 0 25%;
  border-radius: 50%;
  background: repeating-conic-gradient(var(--loader-color, #7c3aed) 0 60deg,var(--loader-secondary-color, #c084fc) 0 120deg);
  transform: translate(-154%,0) rotate(0turn);
  animation: darma-loader-darma-custom-347-l4 3s linear infinite;
}@keyframes darma-loader-darma-custom-347-l4 {to{transform: translate(160%,0) rotate(1turn)}}

